import type { ColorPalette, CustomColorPalette } from './color-palette.js';
/**
 * @public
 */
export type ComparisonOperators = 'equals' | 'not-equals' | 'less-than' | 'less-or-equal' | 'greater-than' | 'greater-or-equal' | 'starts-with' | 'ends-with' | 'contains' | 'not-starts-with' | 'not-ends-with' | 'not-contains' | 'matches-phrase' | 'not-matches-phrase';
/**
 * @public
 */
export type ColorSpecification = {
    color: string;
    colorPalette?: never;
} | {
    color?: never;
    colorPalette: ColorPalette | CustomColorPalette;
};
/**
 * @public
 */
export type MatchValue = string | number | boolean | Date;
/**
 * @public
 */
export type ColorRuleProps = {
    valueAccessor?: string;
    comparator: ComparisonOperators;
    matchValue: MatchValue;
} & ColorSpecification;
